{
  "channels": [
    {
      "name": "chat/messages",
      "description": "Real-time text message delivery",
      "subscribe": {
        "name": "ChatMessageReceived",
        "description": "Incoming text message from another user",
        "fields": {
          "message_id": {
            "type": "string",
            "description": "Unique message ID"
          },
          "conversation_id": {
            "type": "string",
            "description": "Conversation ID"
          },
          "sender_id": {
            "type": "string",
            "description": "Sender user ID"
          },
          "content": {
            "type": "string",
            "description": "Text message content"
          },
          "timestamp": {
            "type": "string",
            "format": "date-time",
            "description": "Message creation time"
          }
        }
      },
      "publish": {
        "name": "SendTextMessage",
        "description": "Send a new text message",
        "fields": {
          "conversation_id": {
            "type": "string",
            "description": "Target conversation ID"
          },
          "content": {
            "type": "string",
            "description": "Text message content"
          },
          "client_message_id": {
            "type": "string",
            "description": "Client-generated id for de-duplication"
          }
        }
      },
      "parameters": {
        "conversation_id": "string"
      }
    },
    {
      "name": "chat/acks",
      "description": "Acknowledgments for message sending",
      "subscribe": {
        "name": "MessageSendAck",
        "description": "Server acknowledgment for sent message",
        "fields": {
          "client_message_id": {
            "type": "string",
            "description": "Client-generated id"
          },
          "message_id": {
            "type": "string",
            "description": "Server-assigned message ID"
          },
          "status": {
            "type": "string",
            "enum": [
              "accepted",
              "rejected"
            ],
            "description": "Send status"
          },
          "timestamp": {
            "type": "string",
            "format": "date-time",
            "description": "Acknowledgment time"
          },
          "error": {
            "type": "string",
            "description": "Error details if rejected"
          }
        }
      }
    }
  ]
}

